import json

def parse(f):
    with open(f) as fp:
        data = json.load(fp)
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs.setdefault(name, {})[p['id']] = p.get('resolvedVersion', p.get('requestedVersion'))
    return pkgs

before = parse('baseline-packages.json')
after = parse('after-cpm-packages.json')

print('Changes:')
for proj in sorted(set(list(before.keys()) + list(after.keys()))):
    for pkg in sorted(set(list(before.get(proj,{}).keys()) + list(after.get(proj,{}).keys()))):
        v1 = before.get(proj,{}).get(pkg)
        v2 = after.get(proj,{}).get(pkg)
        if v1 != v2:
            print(f'  {proj}: {pkg} {v1} -> {v2}')

print()
print('Unchanged packages: all others')
"

